namespace torali {

    class MEI {   
  public:
    inline static const std::string alu = "GGCCGGGCGCGGTGGCTCACGCCTGTAATCCCAGCACTTTGGGAGGCCGAGGCGGGCGGATCACGAGGTCAGGAGATCGAGACCATCCTGGCTAACACGGTGAAACCCCGTCTCTACTAAAAATACAAAAAATTAGCCGGGCGTGGTGGCGGGCGCCTGTAGTCCCAGCTACTCGGGAGGCTGAGGCAGGAGAATGGCGTGAACCCGGGAGGCGGAGCTTGCAGTGAGCCGAGATCGCGCCACTGCACTCCAGCCTGGGCGACAGAGCGAGACTCCGTCTC";
    inline static const std::string sva = "";
    inline static const std::string line1 = "";
    inline static const std::string numt = "";
    inline static const std::string polyA = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA";
  };


  // Tandem repeat detection using autocorrelation.
  inline std::pair<int32_t, float>
  detectTandemRepeat(const std::string& seq, int32_t maxPeriod = 100, float minFraction = 0.85f) {
    int32_t n = (int32_t) seq.size();
    if (n < 10) return {0, 0.0f};
    int32_t pmax = std::min(maxPeriod, n / 2);
    for (int32_t p = 1; p <= pmax; ++p) {
      int32_t matches = 0;
      for (int32_t i = p; i < n; ++i)
	if (seq[i] == seq[i - p]) ++matches;
      if ((float) matches / (float)(n - p) >= minFraction)
	return {p, (float) n / (float) p};
    }
    return {0, 0.0f};
  }

  template<typename TConfig, typename TSVRecord>
  inline void
  annotateSV(TConfig const& c, bam_hdr_t* hdr, char const* seq, TSVRecord& sv) {
    int32_t const chrLen = (int32_t) hdr->target_len[sv.chr];
    const int32_t maxEdits = 2;

    // Extract ALT allele for INS
    std::string altStr;
    std::string insSeq;
    if ((sv.svt == 4) && (!sv.alleles.empty())) {
      std::size_t commaPos = sv.alleles.find(',');
      if (commaPos != std::string::npos) {
	std::string alt = sv.alleles.substr(commaPos + 1);
	if ((alt.size() > 1) && (alt[0] != '<')) {
	  altStr = boost::to_upper_copy(alt);
	  insSeq = altStr.substr(1);
	  if ((int32_t) insSeq.size() > 15000) insSeq = insSeq.substr(0, 15000);
	}
      }
    }

    // Breakpoint homology / TSD detection
    if (sv.svt == 4) {
      // Insertion
      const int32_t maxH_ins = 100;
      if (!altStr.empty()) {
	int32_t limit = std::min({maxH_ins, (int32_t) altStr.size(), chrLen - (sv.svStart - 1)});
	int32_t edits = 0;
	for (int32_t h = 1; h <= limit; ++h) {
	  if (toupper((unsigned char)altStr[h-1]) != toupper((unsigned char)seq[sv.svStart - 1 + h - 1]))
	    if (++edits > maxEdits) break;
	  sv.anno.homLen = h;
	}
      }
    } else if (sv.svEnd > sv.svStart) {
      // DEL/DUP/INV: length-dependent breakpoint homology.
      const int32_t maxH_del = 10000;
      const double minIdentity = 0.90;
      const double stopIdentity = 0.75;
      const int32_t earlyStopGap = 100;

      // Backward scan
      int32_t halfSvLen = (sv.svEnd - sv.svStart) / 2;
      int32_t bwdLimit = std::min({maxH_del, halfSvLen, sv.svStart});
      if (bwdLimit > 0) {
	int32_t edits = 0, lastGoodH = 0;
	for (int32_t h = 1; h <= bwdLimit; ++h) {
	  if (toupper((unsigned char)seq[sv.svStart - h]) != toupper((unsigned char)seq[sv.svEnd - h])) ++edits;
	  double id = 1.0 - (double)edits / h;
	  if (id >= minIdentity) { sv.anno.homLen = h; lastGoodH = h; }
	  else if (h - lastGoodH > earlyStopGap && id < stopIdentity) break;
	}
      }

      // Forward scan
      int32_t fwdLimit = std::max(0, std::min({maxH_del, halfSvLen, chrLen - sv.svEnd - 1}));
      if (fwdLimit > 0) {
	int32_t edits = 0, lastGoodH = 0;
	for (int32_t h = 1; h <= fwdLimit; ++h) {
	  if (toupper((unsigned char)seq[sv.svStart + h]) != toupper((unsigned char)seq[sv.svEnd + h])) ++edits;
	  double id = 1.0 - (double)edits / h;
	  if (id >= minIdentity) { if (h > sv.anno.homLen) sv.anno.homLen = h; lastGoodH = h; }
	  else if (h - lastGoodH > earlyStopGap && id < stopIdentity) break;
	}
      }
    }

    if (!insSeq.empty()) {
      // MEI / NUMT alignment
      double bestId = c.meiMinFrac;
      int32_t bestType = 0;
      double bestFwdId = 0.0;
      double bestRevId = 0.0;

      // undefined, Alu, L1, SVA, NUMT
      static const int32_t meiMinInsLen[] = {0, 100, 150, 400, 50};
      for (int32_t seqtype = 1; seqtype <= 4; ++seqtype) {
	if ((int32_t)insSeq.size() < meiMinInsLen[seqtype]) continue;
	std::string meiTemplate;
	if (seqtype == 1) meiTemplate = MEI::alu;
	else if (seqtype == 2) meiTemplate = MEI::line1;
	else if (seqtype == 3) meiTemplate = MEI::sva;
	else meiTemplate = MEI::numt;
	if (seqtype < 4) meiTemplate += MEI::polyA;
	std::string meiTemplateRC = meiTemplate;
	reverseComplement(meiTemplateRC);

	// Forward alignment
	bool longIns = (insSeq.size() > meiTemplate.size());
	const char* fwdQ = longIns ? meiTemplate.c_str() : insSeq.c_str();
	int32_t fwdQL = longIns ? (int32_t)meiTemplate.size() : (int32_t)insSeq.size();
	const char* fwdT  = longIns ? insSeq.c_str() : meiTemplate.c_str();
	int32_t fwdTL = longIns ? (int32_t)insSeq.size() : (int32_t)meiTemplate.size();
	double fwdId = 0.0;
	EdlibAlignResult resFwd = edlibAlign(fwdQ, fwdQL, fwdT, fwdTL, edlibNewAlignConfig(-1, EDLIB_MODE_HW, EDLIB_TASK_DISTANCE, NULL, 0));
	if ((resFwd.status == EDLIB_STATUS_OK) && (resFwd.editDistance >= 0)) fwdId = 1.0 - (double) resFwd.editDistance / fwdQL;
	edlibFreeAlignResult(resFwd);

	// Reverse alignment
	const char* revQ = longIns ? meiTemplateRC.c_str() : insSeq.c_str();
	int32_t revQL = longIns ? (int32_t)meiTemplateRC.size() : (int32_t)insSeq.size();
	const char* revT  = longIns ? insSeq.c_str() : meiTemplateRC.c_str();
	int32_t revTL = longIns ? (int32_t)insSeq.size() : (int32_t)meiTemplateRC.size();
	double revId = 0.0;
	EdlibAlignResult resRev = edlibAlign(revQ, revQL, revT, revTL, edlibNewAlignConfig(-1, EDLIB_MODE_HW, EDLIB_TASK_DISTANCE, NULL, 0));
	if ((resRev.status == EDLIB_STATUS_OK) && (resRev.editDistance >= 0)) revId = 1.0 - (double) resRev.editDistance / revQL;
	edlibFreeAlignResult(resRev);

	// Find best alignment.
	double coverage = longIns ? ((double)fwdQL / fwdTL) : 1.0;
	double effectiveScore = std::min(std::max(fwdId, revId), coverage);
	if (effectiveScore > bestId) {
	  bestId = effectiveScore;
	  bestType = seqtype;
	  bestFwdId = fwdId;
	  bestRevId = revId;
	}
      }
      if (bestType > 0) {
	sv.anno.seqType = bestType;
	sv.anno.isRC = (bestRevId > bestFwdId);
      } else if ((int32_t) insSeq.size() >= 30) {
	// TR classification
	auto [period, copies] = detectTandemRepeat(insSeq, 100, c.trMinFrac);
	if (period > 0) {
	  sv.anno.seqType = 5;
	  sv.anno.trPeriod = period;
	  sv.anno.trCopies = copies;
	}
      }
    } else if (sv.svt == 2) {
      // DEL: TR classification
      int32_t delLen = sv.svEnd - sv.svStart;
      if ((delLen >= 10) && (delLen <= 1000)) {
	std::string delSeq = boost::to_upper_copy(std::string(seq + sv.svStart, seq + sv.svEnd));
	auto [period, copies] = detectTandemRepeat(delSeq, 100, c.trMinFrac);
	if (period > 0) {
	  sv.anno.seqType = 5;
	  sv.anno.trPeriod = period;
	  sv.anno.trCopies = copies;
	}
      }
    }
  }

}

#endif
